        ref_idx = data['SPY'].index
        n = len(ref_idx)
        close = {s: data[s]['close'].reindex(ref_idx, method='ffill').values.astype(float) for s in all_syms}

        rebal = self.params['rebalance_freq']
        lookback = self.params['lookback']
