        vol_window = self.params['vol_window']
        max_alloc = self.params['max_alloc']
        vix_threshold = self.params['vix_threshold']

        date_to_pos = {s: {d: idx for idx, d in enumerate(out[s].index)} for s in all_syms}
        sig_col = {s: out[s].columns.get_loc('signal') for s in all_syms}
        size_col = {s: out[s].columns.get_loc('size_pct') for s in all_syms}

        def get_ret(s, i, lb):
