                return None
            c = close[s]
            p0, p1 = c[i - lb], c[i]
            if p0 <= 0 or not (np.isfinite(p0) and np.isfinite(p1)):
                return None
            return float(p1 / p0 - 1.0)

        def get_vol(s, i):
            if s not in close or i < vol_window + 1:
                return 0.15
            c = close[s]
            sl = c[i - vol_window:i + 1]
            r = np.diff(np.log(np.maximum(sl, 1e-10)))
