        if not defensive_universe:
            defensive_universe = [equity_universe[-1]] if equity_universe else []

        safe_sym = 'AGG' if 'AGG' in data else (defensive_universe[0] if defensive_universe else None)
        if safe_sym is None or not equity_universe:
